#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=2005;
ll n,mod,jc[N],c[N][N],num[N][N],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>mod;
	jc[0]=1;
	for(int i=1;i<=n;i++) jc[i]=jc[i-1]*i%mod;
	for(int i=0;i<=n;i++) c[i][i]=c[0][i]=1;
	for(int i=0;i<=n;i++)
	{
		for(int j=1;j<n;j++) c[j][i]=(c[j-1][i-1]+c[j][i-1])%mod;
	}
    num[1][1]=1;
    for(int i=2;i<=n;i++)
    {
        for(int j=1;j<=i;j++) num[i][j]=(jc[i-2]*j)%mod*(j-1)%mod;
    }
	for(int i=2;i<=n;i++)
	{
		for(int j=1;j<=n-i+1;j++)
		{
			ans=(ans+(jc[j]*c[j-1][n-i])%mod*j%mod*(n-j)%mod*num[n-j+1][i])%mod;
            // cout<<ans<<"\n";
		}
	}
	cout<<ans;
	return 0;
}
